export interface IEventProcessor {
  readonly supportedPrefixes: string[];
  process(event: WebhookEvent): AsyncResult<void>;
}

export class EventRouter {
  private processors: Map<string, IEventProcessor>;

  async dispatch(event: WebhookEvent): AsyncResult<void> {
    const processor = this.findProcessor(event.eventType);
    if (!processor) {
      logger.warn({ eventType: event.eventType }, 'No processor registered for event type');
      return { ok: true, value: undefined };
    }
    return processor.process(event);
  }
}

export class PaymentProcessor implements IEventProcessor {
  readonly supportedPrefixes = ['payment_intent'];

  async process(event: WebhookEvent): AsyncResult<void> {
    switch (event.eventType) {
      case 'payment_intent.succeeded':
        return this.handleSucceeded(event);
      case 'payment_intent.payment_failed':
        return this.handleFailed(event);
      default:
        logger.info({ eventType: event.eventType }, 'Unhandled payment event subtype');
        return { ok: true, value: undefined };
    }
  }
}

private async handleSucceeded(event: WebhookEvent): AsyncResult<void> {
  const paymentIntent = event.payload.data.object as Stripe.PaymentIntent;
  const existing = await this.paymentService.findByStripeId(paymentIntent.id);
  if (existing && existing.status === 'completed') {
    logger.info({ stripeId: paymentIntent.id }, 'Payment already processed, skipping');
    return { ok: true, value: undefined };
  }
  // proceed with update
}

